using System;

namespace Greyrose.Data
{
    /// <summary>
    /// Captured Ravenwood zone prefix for MSG_LOGINCOMPLETE (zone half of BINSTR payload).
    /// </summary>
    static class DefaultZoneBlob
    {
        const string RavenwoodZonePrefixHex =
            "";

        static byte[] _cached;

        public static byte[] GetBytes()
        {
            if (_cached != null)
                return (byte[])_cached.Clone();

            _cached = CharacterInfoCodec.HexToBytes(RavenwoodZonePrefixHex);
            return (byte[])_cached.Clone();
        }

        public static string GetHex()
        {
            return CharacterInfoCodec.BytesToHex(GetBytes());
        }

        public static void EnsurePlayerStateZoneBlob(PlayerStateRecord state)
        {
            if (state == null || !string.IsNullOrWhiteSpace(state.ZoneBlobHex))
                return;

            state.ZoneBlobHex = GetHex();
        }
    }
}
